def resolve_feature_name(feature_name: str) -> str:
    name = feature_name.strip()
    if not name:
        return ""
    alias = FEATURE_ALIASES.get(name)
    return alias or name


def get_feature_preset(feature_name: str) -> dict | None:
    resolved_name = resolve_feature_name(feature_name)
    preset = FEATURE_PRESETS.get(resolved_name)
    if not preset:
        return None
    return {
        "feature_name": resolved_name,
        **preset,
    }


def is_template_builtin_feature(feature_name: str) -> bool:
    preset = get_feature_preset(feature_name)
    return bool(preset and preset.get("builtin_from_template"))


def build_tab_specs(feature_names: Iterable[str]) -> tuple[list[dict], list[str]]:
    tab_specs: list[dict] = []
    unresolved: list[str] = []
    seen_classes: set[str] = set()

    for raw_name in feature_names:
        preset = get_feature_preset(raw_name)
        resolved_name = resolve_feature_name(raw_name)
        if not preset:
            if resolved_name:
                unresolved.append(resolved_name)
            continue

        tab = preset.get("tab")
        if not tab:
            if resolved_name and resolved_name not in NON_TAB_FEATURES:
                unresolved.append(resolved_name)
            continue

        class_name = str(tab["class_name"])
        if class_name in seen_classes:
            continue

        tab_specs.append(
            {
                "feature_name": preset["feature_name"],
                **tab,
            }
        )
        seen_classes.add(class_name)

    return tab_specs, unresolved


def get_first_business_tab(feature_names: Iterable[str]) -> dict | None:
    for raw_name in feature_names:
        preset = get_feature_preset(raw_name)
        if not preset or preset.get("builtin_from_template"):
            continue
        tab = preset.get("tab")
        if not tab:
            continue
        return {
            "feature_name": preset["feature_name"],
            **tab,
        }
    return None

