#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
from pathlib import Path

from common import (
    DEFAULT_DEST_ROOT,
    DEFAULT_FEATURE_SOURCE_ROOT,
    DEFAULT_TEMPLATE_BUILTIN_FEATURES,
    SOURCE_EXTENSIONS,
    iter_project_files,
    normalize_feature_names,
    normalize_keywords,
    split_feature_names,
    split_keywords,
)


GROUP_ROOTS = {"Controller", "View", "Model", "Manager", "Tool", "Shared", "Resource", "NotSure"}


def detect_module_path(relative_parts: list[str]) -> str:
    if len(relative_parts) < 3:
        return "/".join(relative_parts)

    if len(relative_parts) < 4:
        return "/".join(relative_parts[:2])

    category = relative_parts[2]
    if category not in GROUP_ROOTS:
        return "/".join(relative_parts[:3])

    if len(relative_parts) >= 5 and category != "Tool":
        return "/".join(relative_parts[:4])
    return "/".join(relative_parts[:3])


def score_file(path_text: str, content: str, keywords: list[str]) -> tuple[int, list[str]]:
    score = 0
    matched: list[str] = []
    lowered_path = path_text.lower()
    lowered_content = content.lower()

    for keyword in keywords:
        hit = False
        if keyword in lowered_path:
            score += 6
            hit = True
        count = lowered_content.count(keyword)
        if count:
            score += min(count, 4)
            hit = True
        if hit and keyword not in matched:
            matched.append(keyword)
    return score, matched


def find_feature_matches(feature_root: Path, feature_names: list[str], limit: int) -> dict:
    feature_names = normalize_feature_names(feature_names)
    builtin_features = set(DEFAULT_TEMPLATE_BUILTIN_FEATURES)
    feature_names_for_scan = [name for name in feature_names if name not in builtin_features]
    if not feature_names:
        return {
            "feature_source_root": str(feature_root.resolve()),
            "feature_names": [],
            "template_builtin_features": [],
            "matched_feature_count": 0,
            "matches": [],
            "missing_features": [],
        }
    if not feature_names_for_scan:
        return {
            "feature_source_root": str(feature_root.resolve()),
            "feature_names": feature_names,
            "template_builtin_features": [name for name in feature_names if name in builtin_features],
            "matched_feature_count": 0,
            "matches": [],
            "missing_features": [],
        }

    feature_map = {name.casefold(): name for name in feature_names_for_scan}
    grouped: dict[tuple[str, str], dict] = {}
    matched_features: set[str] = set()

    for path in iter_project_files(feature_root):
        if path.suffix.lower() not in SOURCE_EXTENSIONS and path.name != "Podfile":
            continue

        try:
            relative_parts = list(path.relative_to(feature_root).parts)
        except ValueError:
            continue

        matched_index = -1
        matched_name = ""
        for index, part in enumerate(relative_parts):
            feature_name = feature_map.get(part.strip().casefold())
            if feature_name:
                matched_index = index
                matched_name = feature_name
                break

        if matched_index < 0:
            continue

        module_path = "/".join(relative_parts[: matched_index + 1])
        key = (matched_name, module_path)
        item = grouped.setdefault(
            key,
            {
                "feature_name": matched_name,
                "project": relative_parts[0] if relative_parts else "",
                "module_path": module_path,
                "file_count": 0,
                "files": [],
            },
        )
        item["file_count"] += 1
        item["files"].append(str(path.relative_to(feature_root)))
        matched_features.add(matched_name)

    matches = []
    for item in grouped.values():
        matches.append(
            {
                "feature_name": item["feature_name"],
                "project": item["project"],
                "module_path": item["module_path"],
                "file_count": item["file_count"],
                "files": sorted(item["files"])[:12],
            }
        )
    matches.sort(key=lambda item: (item["feature_name"], item["module_path"]))

    return {
        "feature_source_root": str(feature_root.resolve()),
        "feature_names": feature_names,
        "template_builtin_features": [name for name in feature_names if name in builtin_features],
        "matched_feature_count": len(matched_features),
        "matches": matches[:limit],
        "missing_features": [
            name for name in feature_names_for_scan if name not in matched_features
        ],
    }


def search_modules(
    work_root: Path,
    keywords: list[str],
    limit: int,
    exclude_projects: list[str] | None = None,
    feature_names: list[str] | None = None,
    feature_source_root: Path | None = None,
) -> dict:
    keywords = normalize_keywords(keywords)
    excluded = set(exclude_projects or [])
    grouped: dict[tuple[str, str], dict] = {}
    feature_result = find_feature_matches(feature_source_root or work_root, feature_names or [], limit)

    for path in iter_project_files(work_root):
        if path.suffix.lower() not in SOURCE_EXTENSIONS and path.name != "Podfile":
            continue

        try:
            relative_parts = list(path.relative_to(work_root).parts)
        except ValueError:
            continue

        if not relative_parts:
            continue
        project_name = relative_parts[0]
        if project_name in {"StoryLabmoban", "AAAmoban", "skills"} or project_name in excluded:
            continue

        if len(relative_parts) < 2:
            continue

        try:
            content = path.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue

        searchable_path = "/".join(relative_parts[2:]) if len(relative_parts) > 2 else str(path.relative_to(work_root))
        score, matched_keywords = score_file(searchable_path, content, keywords)
        if score <= 0:
            continue

        module_path = detect_module_path(relative_parts)
        key = (project_name, module_path)
        item = grouped.setdefault(
            key,
            {
                "project": project_name,
                "module_path": module_path,
                "score": 0,
                "matched_keywords": set(),
                "files": [],
            },
        )
        item["score"] += score
        module_path_lower = "/".join(module_path.split("/")[2:]).lower()
        for keyword in matched_keywords:
            if keyword in module_path_lower:
                item["score"] += 12
        item["matched_keywords"].update(matched_keywords)
        item["files"].append(str(path.relative_to(work_root)))

    candidates = []
    for item in grouped.values():
        candidates.append(
            {
                "project": item["project"],
                "module_path": item["module_path"],
                "score": item["score"],
                "matched_keywords": sorted(item["matched_keywords"]),
                "files": sorted(item["files"])[:12],
            }
        )

    candidates.sort(key=lambda item: (-item["score"], item["project"], item["module_path"]))
    return {
        "work_root": str(work_root.resolve()),
        "keywords": keywords,
        "feature_source_root": feature_result["feature_source_root"],
        "feature_names": feature_result["feature_names"],
        "direct_feature_matches": feature_result,
        "candidate_count": len(candidates),
        "candidates": candidates[:limit],
    }


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="按功能名优先、关键词兜底的方式扫描可复用模块")
    parser.add_argument("--keywords", nargs="*", default=[], help="可选关键词，可空格或逗号分隔")
    parser.add_argument("--work-root", default=str(DEFAULT_DEST_ROOT), help="扫描根目录")
    parser.add_argument("--feature-names", nargs="*", default=[], help="优先按中文功能名在 FeatureHub 里找模块")
    parser.add_argument("--feature-source-root", default=str(DEFAULT_FEATURE_SOURCE_ROOT), help="功能目录根路径，默认指向 FeatureHub")
    parser.add_argument("--limit", type=int, default=20, help="最多输出多少个候选模块")
    parser.add_argument("--exclude-projects", nargs="*", default=[], help="要排除的项目目录名")
    return parser


def main() -> None:
    parser = build_parser()
    args = parser.parse_args()
    keywords = split_keywords(args.keywords)
    feature_names = split_feature_names(args.feature_names)
    result = search_modules(
        Path(args.work_root),
        keywords,
        args.limit,
        args.exclude_projects,
        feature_names,
        Path(args.feature_source_root),
    )
    print(json.dumps(result, ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

