def _find_controller_file(app_root: Path, class_name: str) -> Path | None:
    matches = sorted(app_root.rglob(f"{class_name}.m"))
    if not matches:
        return None
    preferred = [path for path in matches if "Controller" in path.parts]
    return preferred[0] if preferred else matches[0]


def _normalize_protocols(protocol_text: str) -> list[str]:
    result: list[str] = []
    for item in protocol_text.split(","):
        protocol = item.strip()
        if protocol and protocol not in result:
            result.append(protocol)
    return result


def _extract_interface_info(content: str, class_name: str) -> tuple[list[str], list[str], int, int] | tuple[None, None, None, None]:
    implementation_anchor = f"@implementation {class_name}"
    implementation_index = content.find(implementation_anchor)
    if implementation_index < 0:
        return None, None, None, None

    pre_impl = content[:implementation_index]
    interface_matches = list(
        re.finditer(rf"@interface\s+{re.escape(class_name)}\s*\(\)\s*(?:<([^>]*)>)?", pre_impl)
    )
    if not interface_matches:
        return None, None, None, None

    start_match = interface_matches[0]
    interface_start = start_match.start()
    macro_start = pre_impl.rfind("#if ENABLE_ADS", max(0, interface_start - 240), interface_start)
    if macro_start >= 0:
        interface_start = macro_start

    interface_end = pre_impl.rfind("@end")
    if interface_end < 0 or interface_end < start_match.end():
        return None, None, None, None
    interface_end += len("@end")

    protocols: list[str] = []
    for match in interface_matches:
        protocol_text = match.group(1) or ""
        for protocol in _normalize_protocols(protocol_text):
            if protocol == "BUNativeExpressBannerViewDelegate":
                continue
            if protocol not in protocols:
                protocols.append(protocol)

    interface_body = pre_impl[start_match.end():interface_end - len("@end")]
    property_lines: list[str] = []
    for line in interface_body.splitlines():
        stripped = line.strip()
        if not stripped:
            property_lines.append("")
            continue
        if stripped.startswith("#if ") or stripped == "#else" or stripped == "#endif":
            continue
        if stripped.startswith("@interface ") or stripped == "@end":
            continue
        if stripped.startswith("#import "):
            continue
        if "BUNativeExpressBannerView *bannerAdView" in stripped:
            continue
        if "CGFloat bannerAdHeight" in stripped:
            continue
        if "Ad Logic" in stripped:
            continue
        property_lines.append(line.rstrip())

    while property_lines and not property_lines[0].strip():
        property_lines.pop(0)
    while property_lines and not property_lines[-1].strip():
        property_lines.pop()

    return protocols, property_lines, interface_start, interface_end


def _build_interface_block(class_name: str, protocols: list[str], property_lines: list[str]) -> str:
    protocol_text = ", ".join(protocols)
    ad_protocols = list(protocols)
    if "BUNativeExpressBannerViewDelegate" not in ad_protocols:
        ad_protocols.append("BUNativeExpressBannerViewDelegate")
    ad_protocol_text = ", ".join(ad_protocols)

    lines = [
        "#if ENABLE_ADS",
        "",
        '#import <BUAdSDK/BUAdSDK.h>',
        '#import "AdManager.h"',
        "",
        f"@interface {class_name} () <{ad_protocol_text}>",
        "",
        "@property(strong, nonatomic) BUNativeExpressBannerView *bannerAdView;",
        "@property(assign, nonatomic) CGFloat bannerAdHeight;",
        "",
        "#else",
        "",
        f"@interface {class_name} ()" + (f" <{protocol_text}>" if protocol_text else ""),
        "",
        "#endif",
        "",
    ]
    if property_lines:
        lines.extend(property_lines)
        lines.append("")
    lines.append("@end")
    return "\n".join(lines)


def _replace_interface_block(content: str, class_name: str) -> tuple[str, bool]:
    protocols, property_lines, start, end = _extract_interface_info(content, class_name)
    if protocols is None or property_lines is None or start is None or end is None:
        return content, False
    interface_block = _build_interface_block(class_name, protocols, property_lines)
    updated = content[:start] + interface_block + content[end:]
    return updated, updated != content


def _ensure_init_banner_height(content: str) -> tuple[str, bool]:
    if "self.bannerAdHeight = ZOOM(75);" in content:
        return content, False

    pattern = re.compile(r"- \(instancetype\)init \{\n.*?\n\}", re.S)
    match = pattern.search(content)
    if not match:
        return content, False

    method = match.group(0)
    anchor = "if (self) {"
    if anchor not in method:
        return content, False

    replacement = (
        anchor
        + "\n\n#if ENABLE_ADS\n\n        self.bannerAdHeight = ZOOM(75);\n        \n#endif"
    )
    updated_method = method.replace(anchor, replacement, 1)
    updated = content[:match.start()] + updated_method + content[match.end():]
    return updated, updated != content


def _ensure_view_will_appear(content: str) -> tuple[str, bool]:
    wrapped_method_pattern = re.compile(
        r"#if ENABLE_ADS\s*- \(void\)viewWillAppear:\(BOOL\)animated \{\n.*?\n\}\s*#endif",
        re.S,
    )
    wrapped_replacement = (
        "#if ENABLE_ADS\n\n"
        "- (void)viewWillAppear:(BOOL)animated {\n"
        "    [super viewWillAppear:animated];\n"
        "    [self groMoreBannerAdLoad]; // 加载banner广告\n"
        "}\n\n"
        "#endif"
    )
    content, replaced_count = wrapped_method_pattern.subn(wrapped_replacement, content, count=1)
    if replaced_count:
        return content, True

    normal_method_pattern = re.compile(r"- \(void\)viewWillAppear:\(BOOL\)animated \{\n.*?\n\}", re.S)
    match = normal_method_pattern.search(content)
    if match:
        method = match.group(0)
        if "groMoreBannerAdLoad" in method:
            return content, False
        anchor = "[super viewWillAppear:animated];"
        if anchor in method:
            replacement = (
                anchor
                + "\n#if ENABLE_ADS\n    [self groMoreBannerAdLoad]; // 加载banner广告\n#endif"
            )
            updated_method = method.replace(anchor, replacement, 1)
            updated = content[:match.start()] + updated_method + content[match.end():]
            return updated, updated != content

    insertion_anchor = content.find("\n#pragma mark - ")
    if insertion_anchor < 0:
        insertion_anchor = content.rfind("\n@end")
    if insertion_anchor < 0:
        return content, False

    block = (
        "\n#if ENABLE_ADS\n\n"
        "- (void)viewWillAppear:(BOOL)animated {\n"
        "    [super viewWillAppear:animated];\n"
        "    [self groMoreBannerAdLoad]; // 加载banner广告\n"
        "}\n\n"
        "#endif\n"
    )
    updated = content[:insertion_anchor] + block + content[insertion_anchor:]
    return updated, True


def _replace_or_append_ad_methods(content: str) -> tuple[str, bool]:
    for match in re.finditer(r"#if ENABLE_ADS[\s\S]*?#endif", content):
        block = match.group(0)
        if "groMoreBannerAdLoad" not in block:
            continue
        if "nativeExpressBannerAdViewDidLoad" not in block and "# pragma mark - GroMore BannerAd" not in block:
            continue
        updated = content[:match.start()] + AD_METHODS_BLOCK + content[match.end():]
        return updated, updated != content

    end_index = content.rfind("\n@end")
    if end_index < 0:
        return content, False
    updated = content[:end_index] + "\n\n" + AD_METHODS_BLOCK + content[end_index:]
    return updated, True


def patch_first_feature_ads(project_dir: Path, project_name: str, feature_names: list[str]) -> dict:
    first_business_tab = get_first_business_tab(feature_names)
    if not first_business_tab:
        return {
            "patched": False,
            "target_feature": "",
            "target_class_name": "",
            "target_file": "",
            "reason": "未找到可承接广告逻辑的首个业务功能",
        }

    class_name = str(first_business_tab["class_name"])
    app_root = project_dir / project_name
    target_file = _find_controller_file(app_root, class_name)
    if not target_file:
        return {
            "patched": False,
            "target_feature": first_business_tab["feature_name"],
            "target_class_name": class_name,
            "target_file": "",
            "reason": "没找到首个业务功能的主控制器文件",
        }

    original_content = target_file.read_text(encoding="utf-8")
    content = original_content.replace("ENABLE_FEATURE_A", "ENABLE_ADS")
    content = content.replace("/******** Feature A Ad Logic *********/", "")
    content, interface_changed = _replace_interface_block(content, class_name)
    content, init_changed = _ensure_init_banner_height(content)
    content, view_will_appear_changed = _ensure_view_will_appear(content)
    content, ad_methods_changed = _replace_or_append_ad_methods(content)

    patched = bool(
        content != original_content
        or interface_changed
        or init_changed
        or view_will_appear_changed
        or ad_methods_changed
    )
    if patched:
        target_file.write_text(content, encoding="utf-8")

    return {
        "patched": patched,
        "target_feature": first_business_tab["feature_name"],
        "target_class_name": class_name,
        "target_file": str(target_file),
        "reason": "",
        "interface_changed": interface_changed,
        "init_changed": init_changed,
        "view_will_appear_changed": view_will_appear_changed,
        "ad_methods_changed": ad_methods_changed,
    }

