def _load_pbxproj_json(pbxproj_path: Path) -> dict:
    completed = subprocess.run(
        ["plutil", "-convert", "json", "-o", "-", str(pbxproj_path)],
        capture_output=True,
        text=True,
        check=True,
    )
    return json.loads(completed.stdout)


