    return None


def _ensure_group(objects: dict, app_group_id: str, group_parts: list[str]) -> str:
    current_group_id = app_group_id
    for part in group_parts:
        existing_group_id = _find_child_group(objects, current_group_id, part)
        if existing_group_id:
