        if (!_isUnlocked && self.actionButton.currentTitle) {
            NSError *error = nil;
            NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:@"(\\d+)" options:0 error:&error];
            NSTextCheckingResult *match = [regex firstMatchInString:self.actionButton.currentTitle
                                                              options:0
                                                                range:NSMakeRange(0, self.actionButton.currentTitle.length)];
            if (match) {
                requiredCoins = [[self.actionButton.currentTitle substringWithRange:[match range]] integerValue];
            }
        }
        self.actionButtonClickBlock(_isUnlocked, requiredCoins);
    }
}


