        [SVProgressHUD showErrorWithStatus:@"Audio session configuration failed"];
        return;
    }
    [session setActive:YES error:&sessionError];
    if (sessionError) {
        [SVProgressHUD showErrorWithStatus:@"Audio session activation failed"];
        return;
    }

    NSError *error = nil;
    self.audioPlayer = [[AVAudioPlayer alloc] initWithContentsOfURL:audioURL error:&error];
    if (error) {
        NSLog(@"Error initializing audio player: %@", error.localizedDescription);
        [SVProgressHUD showErrorWithStatus:@"Failed to initialize audio player"];
        return;
    }

    self.audioPlayer.delegate = self;
    self.audioPlayer.volume = self.volumeSlider.value;
    self.audioPlayer.numberOfLoops = -1;
    [self.audioPlayer prepareToPlay];
    [self.audioPlayer play];

