+ (void)addMemo:(MemoModel *)memo {
    if (!memo.memoId) {
        memo.memoId = [[NSDate date] timeIntervalSince1970];
    }
    if (!memo.createTime) {
        memo.createTime = [NSDate date];
    }
    memo.updateTime = [NSDate date];

    // 置顶的备忘录放在前面
    if (memo.isPinned) {
        [[MemoModel allMemos] insertObject:memo atIndex:0];
    } else {
        [[MemoModel allMemos] addObject:memo];
    }
    [self saveMemos];
}

+ (void)updateMemo:(MemoModel *)memo {
    memo.updateTime = [NSDate date];
    [self saveMemos];
}

+ (void)clearMemo {
    [[MemoModel allMemos] removeAllObjects];
    [self saveMemos];
}

+ (void)deleteMemo:(NSInteger)memoId {
    NSMutableArray *memos = [MemoModel allMemos];
    MemoModel *memoToDelete = nil;

    for (MemoModel *memo in memos) {
        if (memo.memoId == memoId) {
            memoToDelete = memo;
            break;
        }
    }

    if (memoToDelete) {
        [memos removeObject:memoToDelete];
        [self saveMemos];
    }
}

+ (NSArray<MemoModel *> *)searchMemosWithKeyword:(NSString *)keyword {
    if (keyword.length == 0) {
        return [MemoModel allMemos];
    }

    NSPredicate *predicate = [NSPredicate predicateWithFormat:@"title CONTAINS[cd] %@ OR content CONTAINS[cd] %@", keyword, keyword];
    return [[MemoModel allMemos] filteredArrayUsingPredicate:predicate];
}

+ (MemoModel *)memoWithId:(NSInteger)memoId {
    for (MemoModel *memo in [self allMemos]) {
        if (memo.memoId == memoId) {
            return memo;
        }
    }
    return nil;
}

